export function parseAmount(value){const parsed=parseFloat(value);return Number.isFinite(parsed)?parsed:null;}const USD_FORMATTER=new Intl.NumberFormat('en-US',{style:'currency',currency:'USD',minimumFractionDigits:2,maximumFractionDigits:2,});export function normalizeDonationCategory(category){if(!category)return'money';const normalized=String(category).toLowerCase();if(normalized==='items'||normalized==='money'||normalized==='mileage'){return normalized;}return'money';}export function emptyFigure(){return{amount:0,count:0,hasAmount:false};}export function calculateDonationFigures(donations){const figures={total:emptyFigure(),items:emptyFigure(),money:emptyFigure(),mileage:emptyFigure()};for(const donation of donations||[]){const category=normalizeDonationCategory(donation.category);const bucket=figures[category]||figures.money;const amount=parseAmount(donation.amount);figures.total.count+=1;bucket.count+=1;if(amount!==null){figures.total.amount+=amount;figures.total.hasAmount=true;bucket.amount+=amount;bucket.hasAmount=true;}}return figures;}export function formatFigureText(figure){if(!figure)return'$0.00';if(figure.hasAmount)return formatCurrency(figure.amount);if(figure.count>0)return String(figure.count);return'$0.00';}export function formatCurrency(amount){return USD_FORMATTER.format(Number(amount)||0);}